// src/pages/SemesterSelection.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSemestersForYear, getCourseById } from '../config/config';

const SemesterSelection = () => {
  const { courseId, yearId } = useParams();
  const navigate = useNavigate();
  const [semesters, setSemesters] = useState([]);
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSemestersData();
  }, [courseId, yearId]);

  const fetchSemestersData = () => {
    try {
      const courseData = getCourseById(courseId);
      setCourse(courseData);

      if (!courseData) {
        setLoading(false);
        return;
      }

      const yearNum = parseInt(yearId);
      if (yearNum > courseData.duration) {
        console.warn(`Year ${yearNum} not available for ${courseData.name}`);
        setLoading(false);
        return;
      }

      const semestersData = getSemestersForYear(courseId, yearNum);
      setSemesters(semestersData);
    } catch (error) {
      console.error('Error fetching semesters:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSemesterClick = (semesterId) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semesterId}/subjects`);
  };

  const handleBack = () => {
    navigate(`/course/${courseId}`);
  };

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
      }}>
        <div>Loading semesters...</div>
      </div>
    );
  }

  if (!course) {
    return (
      <div style={{
        textAlign: 'center',
        padding: '3rem',
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
      }}>
        <h3>Course not found!</h3>
        <button onClick={handleBack} style={{
          padding: '0.75rem 1.5rem',
          background: '#4f46e5',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer',
          marginTop: '1rem'
        }}>
          ← Back to Courses
        </button>
      </div>
    );
  }

  const yearNum = parseInt(yearId);
  if (yearNum > course.duration) {
    return (
      <div style={{
        textAlign: 'center',
        padding: '3rem',
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
      }}>
        <h3>Invalid Year for {course.name}</h3>
        <p>This course has only {course.duration} years.</p>
        <button onClick={handleBack} style={{
          padding: '0.75rem 1.5rem',
          background: '#4f46e5',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer',
          marginTop: '1rem'
        }}>
          ← Back to Years
        </button>
      </div>
    );
  }

  return (
    <div style={{
      maxWidth: '1200px',
      margin: '0 auto',
      padding: '2rem 1rem',
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
    }}>
      {/* Header */}
      <div style={{ marginBottom: '2rem' }}>
        <button onClick={handleBack} style={{
          padding: '0.75rem 1.5rem',
          background: '#4f46e5',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer',
          fontSize: '1rem',
          marginBottom: '1rem',
          display: 'inline-block'
        }}>
          ← Back to Years
        </button>
        <div style={{
          background: 'white',
          padding: '2rem',
          borderRadius: '15px',
          textAlign: 'center',
          boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
        }}>
          <h1 style={{
            fontSize: '2rem',
            marginBottom: '0.5rem',
            color: '#1f2937'
          }}>
            <span style={{ fontSize: '2rem', marginRight: '0.5rem' }}>{course.icon}</span>
            {course.name} - Year {yearId}
          </h1>
          <p style={{ color: '#6b7280', fontSize: '1.1rem' }}>
            Select your semester (Semester {((yearNum-1)*2)+1} - {yearNum*2})
          </p>
        </div>
      </div>

      {/* Semesters Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
        gap: '1.5rem',
        marginBottom: '2rem'
      }}>
        {semesters.map((semester) => (
          <div
            key={semester.id}
            style={{
              background: 'white',
              padding: '1.5rem',
              borderRadius: '12px',
              cursor: 'pointer',
              transition: 'all 0.3s',
              border: '2px solid transparent',
              boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
              '&:hover': {
                transform: 'translateY(-5px)',
                borderColor: '#4f46e5',
                boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
              }
            }}
            onClick={() => handleSemesterClick(semester.id)}
          >
            <div style={{
              display: 'flex',
              alignItems: 'center',
              gap: '1rem',
              marginBottom: '1rem'
            }}>
              <div style={{
                width: '50px',
                height: '50px',
                background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '1.5rem',
                fontWeight: 'bold',
                color: 'white'
              }}>
                {semester.number}
              </div>
              <h3 style={{ fontSize: '1.25rem', color: '#1f2937' }}>
                {semester.name}
              </h3>
            </div>

            <div style={{
              display: 'flex',
              gap: '1.5rem',
              margin: '1rem 0',
              fontSize: '0.9rem'
            }}>
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                <span style={{ color: '#666', fontSize: '0.8rem' }}>Subjects:</span>
                <span style={{ fontWeight: 'bold', fontSize: '1.1rem', color: '#4f46e5' }}>
                  {semester.subjects}
                </span>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                <span style={{ color: '#666', fontSize: '0.8rem' }}>Credits:</span>
                <span style={{ fontWeight: 'bold', fontSize: '1.1rem', color: '#4f46e5' }}>
                  {semester.credits}
                </span>
              </div>
            </div>

            <div style={{
              display: 'flex',
              flexWrap: 'wrap',
              gap: '0.5rem',
              margin: '1rem 0'
            }}>
              <span style={{
                background: '#e0e7ff',
                color: '#4f46e5',
                padding: '0.3rem 0.8rem',
                borderRadius: '15px',
                fontSize: '0.8rem'
              }}>
                Syllabus
              </span>
              <span style={{
                background: '#e0e7ff',
                color: '#4f46e5',
                padding: '0.3rem 0.8rem',
                borderRadius: '15px',
                fontSize: '0.8rem'
              }}>
                Notes
              </span>
              <span style={{
                background: '#e0e7ff',
                color: '#4f46e5',
                padding: '0.3rem 0.8rem',
                borderRadius: '15px',
                fontSize: '0.8rem'
              }}>
                PYQs
              </span>
              <span style={{
                background: '#e0e7ff',
                color: '#4f46e5',
                padding: '0.3rem 0.8rem',
                borderRadius: '15px',
                fontSize: '0.8rem'
              }}>
                Lab Files
              </span>
            </div>

            <button style={{
              marginTop: '1rem',
              padding: '0.75rem',
              width: '100%',
              background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: 'pointer',
              fontSize: '0.9rem',
              fontWeight: '500'
            }}>
              View Subjects →
            </button>
          </div>
        ))}
      </div>

      {/* Year Info */}
      <div style={{
        background: 'white',
        padding: '1.5rem',
        borderRadius: '12px',
        textAlign: 'center',
        boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
        color: '#6b7280'
      }}>
        <h3>📚 Year {yearId} Information</h3>
        <p>
          Semesters: {((yearNum-1)*2)+1} & {yearNum*2} • 
          Total Credits: {semesters.reduce((sum, sem) => sum + sem.credits, 0)} • 
          Total Subjects: {semesters.reduce((sum, sem) => sum + sem.subjects, 0)}
        </p>
      </div>
    </div>
  );
};

export default SemesterSelection;
